  ('social-worker-moex-06010', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關老年人「社會支持」之敘述，何者錯誤？', '["社會支持能夠使老年人保有幸福感", "社會支持與老年人的身心健康有明顯的關係", "老年人基本的社會支持來源，通常來自於家庭成員", "重新連結老年人既有的社會支持網絡比協助他們建立新的社會支持網絡，更為重要"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06011', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '詢問一位沒有弟弟或妹妹的2～5歲兒童以下問題：「一個4歲大的孩子叫做小華，她有沒有姊姊？兒童 回答：『有，她的姊姊叫做大華』，接著再問，那大華有沒有妹妹？兒童回答：『沒有』」。這代表他 的認知發展，有下列那種特性？', '["缺乏可逆性思考", "自我中心主義", "萬物有靈論", "平行推理思考"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06012', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「更年期」的敘述，何者錯誤？', '["每個女性更年期的生理症狀都不盡相同", "不同文化會以不同態度來面對更年期", "男性因為生理構造與女性不同，不會遇到更年期的困擾", "若是女性將更年期解讀為生命中必經過程，則比較不會產生負面的情緒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06013', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '為了創造具有意義與滿足的老年生活，下列何者並非Peck（1968）所建議的心理調適方法？', '["將對自我的熱衷轉換至自我超越", "將對身體的熱衷轉換至身體的超然", "將工作角色的熱衷轉換至自我分化", "將對社會參與的熱衷轉換至休閒娛樂"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06014', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '嬰兒在9個月大時，對於不熟悉的人會有恐懼和退縮的反應，此一理論是由下列那一個學者所提出？', '["佛洛伊德的心理動力理論", "皮亞傑的認知理論", "班度拉的社會學習理論", "艾瑞克森的生命週期理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06015', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關兒童道德發展的理論觀點，下列敘述何者正確？', '["佛洛伊德主張，父母用嚴格的方法阻止兒童的衝動時，兒童的超我發展程度較低", "社會學習理論強調兒童會複製被懲罰的行為", "柯柏格的道德發展階段，不是循序而進", "有關佛洛伊德、皮亞傑、柯柏格提出的兒童道德發展理論觀點，都遺漏同理心及設身處地等兩項要素"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06016', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關生命歷程觀點，下列何項敘述錯誤？', '["生命歷程觀點的主要概念，包括世代、過渡期、軌跡、生命事件、轉捩點", "生命歷程觀點可以涵蓋巨視社會文化結構面與正式的大型組織", "兒童期至青少年期，其風險因子為貧窮、兒童虐待、父母離婚等", "運用社工個案管理的介入與助力，以促進個人、家庭、社區及組織轉化危機，重新回到健康的常軌"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06017', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '針對中年人的發展任務，下列何項不是社會工作者的角色功能？', '["統整人生與規劃多元居住安排", "協助覺察「合宜的中年角色」", "引導評估中年人生理變化和健康議題", "探索中年人個人對生產力與傳承活動的參與"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06018', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '家庭暴力是危害孕婦和胎兒的因素之一，有關社會工作者處遇受虐孕婦時的認知與技巧，下列何項敘述 錯誤？', '["受虐婦女容易造成流產、早產及嬰兒體重不足", "在進行訪談時，應該將受虐婦女與案夫隔離", "受虐婦女必須訂出一套安全策略保護自己", "受虐婦女會因受虐而拒絕吸菸、吸毒、酗酒等不良健康習慣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06019', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Sleek指出，社會工作者可透過某些方式幫助有主觀同性戀恐懼症的案主，下列何者非屬Sleek提出之方式？', '["與案主討論他的早期經驗，以及他如何因應面對自己是同性戀的感受", "鼓勵案主與愛滋病的病友相互支持，建立支持系統", "挑戰案主對性別角色的認定及想法", "社會工作者提供一個正向的角色模範"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
